### Load quad and WAB data


::: {.cell}

```{.r .cell-code}
library(rlang)
library(cbbplotR)
options(chromote.headless = "new")

# this data is used in the evidence app, saving as a csv for static generation 
# https://github.com/gallochris/evdev-byc/blob/main/data/college-basketball/wab_logs.R
team_sched_by_wab <- readr::read_csv("team_sched_by_wab.csv")

quad_fun <- team_sched_by_wab |> 
  dplyr::filter(quad == "Q1") |> 
  dplyr::filter(team %in% c(
    "North Carolina", "Indiana", "Gonzaga")) |> 
  dplyr::mutate(location = factor(location, levels = c("H", "A", "N"))) |> 
  dplyr::group_by(team) |> 
  dplyr::mutate(
    wins = sum(result == "W"),
    games = dplyr::n(),
    win_pct = wins / games,
    total_wab = sum(wab_result),
    avg_bub_win_prob = mean(bub_win_prob),
    team_label = sprintf("%s\n(%d-%d)", team, wins, games - wins)
  ) |>
  dplyr::filter(games > 1) |> 
  dplyr::ungroup() |> 
  dplyr::mutate(team_label = forcats::fct_reorder(team_label, win_pct)) 
```
:::


### Q1 Plot 


::: {.cell}

```{.r .cell-code}
q1_plot <- quad_fun |> 
  ggplot2::ggplot(ggplot2::aes(x = bub_win_prob, y = team_label, 
                               shape = location, color = result)) +
  ggplot2::geom_vline(xintercept = c(0.1, .25, .45), linetype = "dashed", color = "#333333", alpha = 0.5) +
  ggplot2::geom_point(
    size = 4, stroke = 1.5, alpha = 0.9, 
    position = ggplot2::position_jitter(width = 0.02, height = 0)
  ) + 
  ggplot2::scale_shape_manual(
    values = c("H" = 1, "A" = 2, "N" = 0), 
    name = "Location",
    labels = c("Home", "Away", "Neutral")
  ) +
  ggplot2::scale_color_manual(
    values = c("W" = "#4d9221", "L" = "#c51b7d"),
    name = "Result",
    labels = c("Win", "Loss")
  ) +
  ggplot2::labs(
    x = "Bubbble Team Win Probability", 
    y = NULL, 
    title = "Not all Q1 games are created equal",
    subtitle =  "Plots Q1 games for bubble teams showing by odds that a bubble team would win the game.<br>
