### Lineup table 


::: {.cell}

```{.r .cell-code}
lineup_tbl <- all_lineups |>
  gt::gt(
    groupname_col = c("label_group"),
    process_md = TRUE,
    row_group_as_column = FALSE,
  ) |>
  gtUtils::gt_theme_gtutils() |>
  gt::cols_align(columns = c(category), align = "left") |>
  gtUtils::gt_column_subheaders(
    PercentMins = list(heading = "Minutes", subtitle = "% played"),
    NETRTG = list(heading = "NET", subtitle = "Rating"),
    ORTG = list(heading = "Offense", subtitle = "Rating"),
    DRTG = list(heading = "Defense", subtitle = "Rating"),
    ORBper = list(heading = "Rebound %", subtitle = "Offense"),
    heading_color = "black",
    subtitle_color = "gray"
  ) |>
  gt::cols_label(category = "") |>
  gtExtras::gt_add_divider(columns = c(category),
                           sides = "right",
                           color = "black") |>
  gt::data_color(
    columns = NETRTG,
    direction = c("column"),
    method = c("numeric"),
    palette = c("lightpink", "lightgreen"),
    alpha = 0.6
  ) |>
  gt::tab_header(
    title = gt::html("North Carolina: Lineups using two, three, or four guards"),
    subtitle = gt::html(
      "Shows lineup ratings when using a different amount of guards over the course of the season.<br>Carolina is 18-11 overall through February 24 games."
    )
  ) |>
  gt::tab_source_note(
    source_note =
      gt::html(
        "<hr>Data via bigballR & theme via {gtUtils}<br> NET Rating shows based on points per possession and not per 100 possessions.<hr>
        <b>Table by Ryan (5thFactor) and Chris at Bless your chart</b>"
      )
  ) |>
  gt::tab_style(
    locations = gt::cells_column_spanners(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      weight = 850,
      size = gt::px(15)
    )
  ) |>
  gt::tab_style(
    locations = gt::cells_source_notes(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      size = gt::px(11.5),
      weight = 250
    )
  ) |>
  gt::tab_style(style = list(gt::cell_text(font = gt::google_font("Signika Negative"))),
                locations = gt::cells_body(columns = c(category))) |>
  gt::tab_style(
    style = list(gt::cell_text(color = "#7fc97f", weight = "bold")),
    locations = gt::cells_body(columns = c(category), rows = c(1, 4))
  ) |>
  gt::tab_style(
    style = list(gt::cell_text(color = "#beaed4", weight = "bold")),
    locations = gt::cells_body(columns = c(category), rows = c(2, 5))
  ) |>
  gt::tab_style(
    style = list(gt::cell_text(color = "#e6853a", weight = "bold")),
    locations = gt::cells_body(columns = c(category), rows = c(3, 6))
  ) |>
  gt::tab_style(
    locations = gt::cells_row_groups(),
    style = list(
      gt::cell_text(
        font = gt::google_font("Signika Negative"),
        weight = 850,
        size = gt::px(12),
        color = "black",
        align = "left"
