### Lineup plot 


::: {.cell}

```{.r .cell-code}
lineup_plot <- unc_gf_season |> 
  dplyr::mutate(
    Date = as.Date(date, origin = "1970-01-01"),
    Lineup = dplyr::case_when(
      category == "FF" ~ "2-Guard",
      category == "GF" ~ "3-Guard",
      category == "GG" ~ "4-Guard"
    )
  ) |> 
  dplyr::rename(Minutes = mins) |> 
  ggplot2::ggplot(ggplot2::aes(x = Date, y = Minutes, col = Lineup)) +
  ggplot2::geom_point(size = 2) +
  ggplot2::geom_line(alpha = .2, size = 1.5) +
  ggplot2::geom_smooth(formula = "y~x", method = "loess", se = FALSE, span = .5, size = 2) +
  ggplot2::scale_x_date(labels = scales::date_format("%B"), date_breaks = "1 month") +
  ggplot2::scale_color_manual(values = c("#7fc97f",
                               "#beaed4",
                               "#e6853a")) +
  ggplot2::labs(
    title = "North Carolina: Lineup types per game for 2024-25 Season",
    subtitle =  "Shows lineups using <span style='color: #7fc97f;'><b>2-Guards</span></b>, 
    <span style='color: #beaed4;'><b>3-Guards</span></b>, and 
    <span style='color: #e6853a;'><b>4-Guards</span></b> over the season.<br>
    Carolina is 18-11 overall through February 24 games.",
    x = "",
    y = "Minutes",
    caption = "Data via bigballR through February 24 games  \nViz by Ryan (5thFactor) + Chris at Bless your Chart"
  ) +
  hrbrthemes::theme_ipsum_rc() +
  ggplot2::theme(
    plot.title = ggplot2::element_text(
      hjust = 0.5,
      size = 16,
      family = "Roboto Condensed"
    ),
    plot.subtitle = ggtext::element_markdown(
      hjust = 0.5,
      size = 9.5,
      lineheight = 1.5,
      family = "Roboto Condensed"
    ),
    legend.position = "none",
    axis.text.y = ggplot2::element_text(size = 10, family = "Roboto Condensed"),
    axis.text.x = ggplot2::element_text(size = 10, family = "Roboto Condensed"),
    axis.title.x = ggplot2::element_text(hjust = 0.5),
    plot.caption = ggplot2::element_text(face = "plain", size = 8, "Roboto Condensed"),
  )


ggplot2::ggsave(
